class User_File_Upload_Manager {
    
    private $upload_dir;
    private $allowed_types = array(
        'image/jpeg',
        'image/jpg',
        'image/png',
        'image/gif',
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-excel',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    );
    
    public function __construct() {
        $this->upload_dir = WP_CONTENT_DIR . '/uploads/user-files/';
        
        add_action('init', array($this, 'create_upload_directory'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_scripts'));
        add_shortcode('user_file_upload', array($this, 'render_upload_form'));
        add_action('wp_ajax_upload_user_file', array($this, 'handle_file_upload'));
        add_action('wp_ajax_delete_user_file', array($this, 'handle_file_delete'));
        add_action('wp_ajax_get_user_files', array($this, 'get_user_files'));
        add_action('show_user_profile', array($this, 'add_profile_fields'));
        add_action('edit_user_profile', array($this, 'add_profile_fields'));
    }
    
    public function create_upload_directory() {
        if (!file_exists($this->upload_dir)) {
            wp_mkdir_p($this->upload_dir);
            file_put_contents($this->upload_dir . '.htaccess', 'Options -Indexes');
        }
    }
    
    public function enqueue_scripts() {
        wp_enqueue_style('user-file-upload-css', plugin_dir_url(__FILE__) . 'assets/style.css', array(), '1.0');
        wp_enqueue_script('user-file-upload-js', plugin_dir_url(__FILE__) . 'assets/script.js', array('jquery'), '1.0', true);
        wp_localize_script('user-file-upload-js', 'userFileUpload', array(
            'ajax_url' => admin_url('admin-ajax.php'),
            'nonce' => wp_create_nonce('user_file_upload_nonce')
        ));
    }
    
    public function render_upload_form($atts) {
        if (!is_user_logged_in()) {
            return '<p>You must be logged in to upload files.</p>';
        }
        
        $user_id = get_current_user_id();
        $user_files = $this->get_user_uploaded_files($user_id);
        $profile_picture = get_user_meta($user_id, 'profile_picture', true);
        
        ob_start();
        ?>
        <div class="user-file-upload-container">
            <div class="profile-picture-section">
                <h3>Profile Picture</h3>
                <div class="profile-picture-preview">
                    <?php if ($profile_picture && file_exists($profile_picture)): ?>
                        <img src="<?php echo esc_url(content_url('uploads/user-files/' . basename($profile_picture))); ?>" alt="Profile Picture" class="current-profile-pic">
                    <?php else: ?>
                        <div class="no-profile-pic">No profile picture</div>
                    <?php endif; ?>
                </div>
                <form id="profile-picture-form" enctype="multipart/form-data">
                    <input type="file" name="profile_picture" id="profile_picture" accept="image/*" required>
                    <input type="hidden" name="file_type" value="profile_picture">
                    <button type="submit" class="upload-btn">Upload Profile Picture</button>
                </form>
                <div class="upload-message profile-message"></div>
            </div>
            
            <div class="documents-section">
                <h3>Upload Documents</h3>
                <form id="document-upload-form" enctype="multipart/form-data">
                    <label for="document_file">Select File:</label>
                    <input type="file" name="document_file" id="document_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.xls,.xlsx" required>
                    <label for="file_description">Description (optional):</label>
                    <input type="text" name="file_description" id="file_description" placeholder="Enter file description">
                    <input type="hidden" name="file_type" value="document">
                    <button type="submit" class="upload-btn">Upload Document</button>
                </form>
                <div class="upload-message document-message"></div>
            </div>
            
            <div class="uploaded-files-section">
                <h3>Your Uploaded Files</h3>
                <div class="uploaded-files-list">
                    <?php if (!empty($user_files)): ?>
                        <?php foreach ($user_files as $file): ?>
                            <div class="file-item" data-file-id="<?php echo esc_attr($file['id']); ?>">
                                <div class="file-info">
                                    <span class="file-name"><?php echo esc_html($file['filename']); ?></span>
                                    <?php if (!empty($file['description'])): ?>
                                        <span class="file-description"><?php echo esc_html($file['description']); ?></span>
                                    <?php endif; ?>
                                    <span class="file-date"><?php echo esc_html($file['upload_date']); ?></span>
                                </div>
                                <div class="file-actions">
                                    <a href="<?php echo esc_url(content_url('uploads/user-files/' . $file['filename'])); ?>" target="_blank" class="file-download">Download</a>
                                    <button class="file-delete" data-file-id="<?php echo esc_attr($file['id']); ?>">Delete</button>
                                </div>
                            </div>
                        <?php endforeach; ?>
                    <?php else: ?>
                        <p class="no-files">No files uploaded yet.</p>
                    <?php endif; ?>
                </div>
            </div>
        </div>
        <?php
        return ob_get_clean();
    }
    
    public function handle_file_upload() {
        check_ajax_referer('user_file_upload_nonce', 'nonce');
        
        if (!is_user_logged_in()) {
            wp_send_json_error(array('message' => 'You must be logged in to upload files.'));
        }
        
        $user_id = get_current_user_id();
        $file_type = sanitize_text_field($_POST['file_type']);
        
        if ($file_type === 'profile_picture') {
            if (!isset($_FILES['profile_picture']) || $_FILES['profile_picture']['error'] !== UPLOAD_ERR_OK) {
                wp_send_json_error(array('message' => 'File upload error.'));
            }
            
            $file = $_FILES['profile_picture'];
            $this->process_profile_picture($file, $user_id);
        } else {
            if (!isset($_FILES['document_file']) || $_FILES['document_file']['error'] !== UPLOAD_ERR_OK) {
                wp_send_json_error(array('message' => 'File upload error.'));
            }
            
            $file = $_FILES['document_file'];
            $description = sanitize_text_field($_POST['file_description']);
            $this->process_document($file, $user_id, $description);
        }
    }
    
    private function process_profile_picture($file, $user_id) {
        $file_type = mime_content_type($file['tmp_name']);
        
        if (!in_array($file_type, array('image/jpeg', 'image/jpg', 'image/png', 'image/gif'))) {
            wp_send_json_error(array('message' => 'Invalid file type. Only images are allowed for profile pictures.'));
        }
        
        if ($file['size'] > 5242880) {
            wp_send_json_error(array('message' => 'File size exceeds 5MB limit.'));
        }
        
        $old_profile_pic = get_user_meta($user_id, 'profile_picture', true);
        if ($old_profile_pic && file_exists($old_profile_pic)) {
            unlink($old_profile_pic);
        }
        
        $user_dir = $this->upload_dir . $user_id . '/';
        if (!file_exists($user_dir)) {
            wp_mkdir_p($user_dir);
        }
        
        $extension = pathinfo($file['name'], PATHINFO_EXTENSION);
        $filename = 'profile_' . time() . '.' . $extension;
        $filepath = $user_dir . $filename;
        
        if (move_uploaded_file($file['tmp_name'], $filepath)) {
            update_user_meta($user_id, 'profile_picture', $filepath);
            wp_send_json_success(array(
                'message' => 'Profile picture uploaded successfully!',
                'file_url' => content_url('uploads/user-files/' . $user_id . '/' . $filename)
            ));
        } else {
            wp_send_json_error(array('message' => 'Failed to save file.'));
        }
    }
    
    private function process_document($file, $user_id, $description) {
        $file_type = mime_content_type($file['tmp_name']);
        
        if (!in_array($file_type, $this->allowed_types)) {
            wp_send_json_error(array('message' => 'Invalid file type.'));
        }
        
        if ($file['size'] > 10485760) {
            wp_send_json_error(array('message' => 'File size exceeds 10MB limit.'));
        }
        
        $user_dir = $this->upload_dir . $user_id . '/';
        if (!file_exists($user_dir)) {
            wp_mkdir_p($user_dir);
        }
        
        $extension = pathinfo($file['name'], PATHINFO_EXTENSION);
        $filename = sanitize_file_name(pathinfo($file['name'], PATHINFO_FILENAME)) . '_' . time() . '.' . $extension;
        $filepath = $user_dir . $filename;
        
        if (move_uploaded_file($file['tmp_name'], $filepath)) {
            $file_meta = get_user_meta($user_id, 'uploaded_documents', true);
            if (!is_array($file_meta)) {
                $file_meta = array();
            }
            
            $file_id = uniqid();
            $file_meta[$file_id] = array(
                'id' => $file_id,
                'filename' => $filename,
                'filepath' => $filepath,
                'description' => $description,
                'upload_date' => current_time('mysql'),
                'file_type' => $file_type
            );
            
            update_user_meta($user_id, 'uploaded_documents', $file_meta);
            
            wp_send_json_success(array(
                'message' => 'Document uploaded successfully!',
                'file' => $file_meta[$file_id]
            ));
        } else {
            wp_send_json_error(array('message' => 'Failed to save file.'));
        }
    }
    
    public function handle_file_delete() {
        check_ajax_referer('user_file_upload_nonce', 'nonce');
        
        if (!is_user_logged_in()) {
            wp_send_json_error(array('message' => 'You must be logged in.'));
        }
        
        $user_id = get_current_user_id();
        $file_id = sanitize_text_field($_POST['file_id']);
        
        $file_meta = get_user_meta($user_id, 'uploaded_documents', true);
        
        if (isset($file_meta[$file_id])) {
            if (file_exists($file_meta[$file_id]['filepath'])) {
                unlink($file_meta[$file_id]['filepath']);
            }
            
            unset($file_meta[$file_id]);
            update_user_meta($user_id, 'uploaded_documents', $file_meta);
            
            wp_send_json_success(array('message' => 'File deleted successfully.'));
        } else {
            wp_send_json_error(array('message' => 'File not found.'));
        }
    }
    
    public function get_user_files() {
        check_ajax_referer('user_file_upload_nonce', 'nonce');
        
        if (!is_user_logged_in()) {
            wp_send_json_error(array('message' => 'You must be logged in.'));
        }
        
        $user_id = get_current_user_id();
        $files = $this->get_user_uploaded_files($user_id);
        
        wp_send_json_success(array('files' => $files));
    }
    
    private function get_user_uploaded_files($user_id) {
        $file_meta = get_user_meta($user_id, 'uploaded_documents', true);
        
        if (!is_array($file_meta)) {
            return array();
        }
        
        return array_values($file_meta);
    }
    
    public function add_profile_fields($user) {
        if (!current_user_can('edit_user', $user->ID)) {
            return;
        }
        
        $profile_picture = get_user_meta($user->ID, 'profile_picture', true);
        $user_files = $this->get_user_uploaded_files($user->ID);
        ?>
        <h3>User Files</h3>
        <table class="form-table">
            <tr>
                <th>Profile Picture</th>
                <td>
                    <?php if ($profile_picture && file_exists($profile_picture)): ?>
                        <img src="<?php echo esc_url(content_url('uploads/user-files/' . $user->ID . '/' . basename($profile_picture))); ?>" style="max-width: 150px; height: auto;">
                    <?php else: ?>
                        <p>No profile picture uploaded.</p>
                    <?php endif; ?>
                </td>
            </tr>
            <tr>
                <th>Uploaded Documents</th>
                <td>
                    <?php if (!empty($user_files)): ?>
                        <ul>
                            <?php foreach ($user_files as $file): ?>
                                <li>
                                    <strong><?php echo esc_html($file['filename']); ?></strong>
                                    <?php if (!empty($file['description'])): ?>
                                        - <?php echo esc_html($file['description']); ?>
                                    <?php endif; ?>
                                    (<?php echo esc_html($file['upload_date']); ?>)
                                </li>
                            <?php endforeach; ?>
                        </ul>
                    <?php else: ?>
                        <p>No documents uploaded.</p>
                    <?php endif; ?>
                </td>
            </tr>
        </table>
        <?php
    }
}

