$js_content = 'jQuery(document).ready(function($) {
    $("#profile-picture-form").on("submit", function(e) {
        e.preventDefault();
        
        var formData = new FormData(this);
        formData.append("action", "upload_user_file");
        formData.append("nonce", userFileUpload.nonce);
        
        $.ajax({
            url: userFileUpload.ajax_url,
            type: "POST",
            data: formData,
            processData: false,
            contentType: false,
            success: function(response) {
                if (response.success) {
                    $(".profile-message").removeClass("error").addClass("success").text(response.data.message).show();
                    setTimeout(function() {
                        location.reload();
                    }, 1500);
                } else {
                    $(".profile-message").removeClass("success").addClass("error").text(response.data.message).show();
                }
            },
            error: function() {
                $(".profile-message").removeClass("success").addClass("error").text("An error occurred.").show();
            }
        });
    });
    
    $("#document-upload-form").on("submit", function(e) {
        e.preventDefault();
        
        var formData = new FormData(this);
        formData.append("action", "upload_user_file");
        formData.append("nonce", userFileUpload.nonce);
        
        $.ajax({
            url: userFileUpload.ajax_url,
            type: "POST",
            data: formData,
            processData: false,
            contentType: false,
            success: function(response) {
                if (response.success) {
                    $(".document-message").removeClass("error").addClass("success").text(response.data.message).show();
                    $("#document-upload-form")[0].reset();
                    setTimeout(function() {
                        location.reload();
                    }, 1500);
                } else {
                    $(".document-message").removeClass("success").addClass("error").text(response.data.message).show();
                }
            },
            error: function() {
                $(".document-message").removeClass("success").addClass("error").text("An error occurred.").show();
            }
        });
    });
    
    $(".file-delete").on("click", function() {
        if (!confirm("Are you sure you want to delete this file?")) {
            return;
        }
        
        var fileId = $(this).data("file-id");
        var fileItem = $(this).closest(".file-item");
        
        $.ajax({
            url: userFileUpload.ajax_url,
            type: "POST",
            data: {
                action: "delete_user_file",
                nonce: userFileUpload.nonce,
                file_id: fileId
            },
            success: function(response) {
                if (response.success) {
                    fileItem.fadeOut(300, function() {
                        $(this).remove();
                        if ($(".file-item").length === 0) {
                            $(".uploaded-files-list").html("<p class=\"no-files\">No files uploaded yet.</p>");
                        }
                    });
                } else {
                    alert(response.data.message);
                }
            },
            error: function() {
                alert("An error occurred while deleting the file.");
            }
        });
    });
});';

